CREATE TABLE api_keys (id VARCHAR(36) NOT NULL, name VARCHAR(120) NOT NULL, prefix CHAR(12) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, salt BINARY(16) NOT NULL, secret_hash BINARY(32) NOT NULL, expires_at DATETIME(6) NULL, revoked_at DATETIME(6) NULL, last_used_at DATETIME(6) NULL, rotated_from_id VARCHAR(36) NULL, replaced_by_id VARCHAR(36) NULL, created_by VARCHAR(64) NOT NULL, created_at DATETIME(6) NOT NULL, PRIMARY KEY (id), UNIQUE KEY uq_api_keys_prefix (prefix), UNIQUE KEY uq_api_keys_rotated_from (rotated_from_id), UNIQUE KEY uq_api_keys_replaced_by (replaced_by_id), KEY idx_api_keys_list (created_at DESC,id DESC), KEY idx_api_keys_status (revoked_at,expires_at,created_at DESC,id DESC), CONSTRAINT fk_api_keys_created_by FOREIGN KEY (created_by) REFERENCES users (id), CONSTRAINT fk_api_keys_rotated_from FOREIGN KEY (rotated_from_id) REFERENCES api_keys (id), CONSTRAINT fk_api_keys_replaced_by FOREIGN KEY (replaced_by_id) REFERENCES api_keys (id), CONSTRAINT chk_api_keys_prefix CHECK (prefix REGEXP _ascii'^[a-z2-7]{12}$'), CONSTRAINT chk_api_keys_rotation CHECK (rotated_from_id IS NULL OR rotated_from_id<>id), CONSTRAINT chk_api_keys_replacement CHECK (replaced_by_id IS NULL OR replaced_by_id<>id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
